const VALID_CATEGORIES = new Set([
  'pharmacy', 'fuel_station', 'mobile_money',
  'alcohol_outlet', 'billboard', 'transport_road', 'census_proxy',
]);
const CATEGORY_ALIASES = {
  fuel: 'fuel_station', petrol: 'fuel_station', gas: 'fuel_station',
  pharmacy: 'pharmacy', chemist: 'pharmacy', drugstore: 'pharmacy',
  mobile_money: 'mobile_money', momo: 'mobile_money', mobile_payment: 'mobile_money',
  alcohol: 'alcohol_outlet', bar: 'alcohol_outlet', pub: 'alcohol_outlet',
  billboard: 'billboard', advertising: 'billboard',
  road: 'transport_road', transport: 'transport_road',
  census: 'census_proxy', household: 'census_proxy',
};
function normalizeCategory(raw) {
  if (!raw) return null;
  const lower = String(raw).trim().toLowerCase().replace(/[^a-z_]/g, '_');
  if (VALID_CATEGORIES.has(lower)) return lower;
  const alias = CATEGORY_ALIASES[lower];
  return alias ?? null;
}

const sourceSystem = typeof $json.sourceSystem === 'string' ? $json.sourceSystem : 'competitor_feed';
const records = Array.isArray($json.records) ? $json.records : [];
const blocked = ['google_maps'];
if (blocked.includes(sourceSystem)) {
  throw new Error('Blocked sourceSystem. Review ToS before enabling this feed.');
}

const leads = [];
const skipped = [];
records.forEach((row, index) => {
  const category = normalizeCategory(row.category ?? row.vertical);
  if (!category) {
    skipped.push({ index, raw: row.category ?? row.vertical ?? null });
    return;
  }
  leads.push({
    sourceRecordId: String(row.sourceRecordId ?? `${sourceSystem}-${index}`),
    sourceUrl: row.sourceUrl ?? null,
    category,
    location: {
      latitude: Number(row.latitude ?? row.lat),
      longitude: Number(row.longitude ?? row.lon),
    },
    normalizedDetails: row.normalizedDetails ?? {
      name: row.name ?? null,
      brand: row.brand ?? null,
      operator: row.operator ?? null,
    },
    rawPayload: row,
    evidenceUrls: Array.isArray(row.evidenceUrls) ? row.evidenceUrls : [],
    freshnessAt: row.freshnessAt ?? new Date().toISOString(),
    priority: row.priority ?? 'medium',
  });
});

if (skipped.length > 0) {
  console.warn(`[adl-competitor-leads] Skipped ${skipped.length}/${records.length} rows with unmapped categories:`, JSON.stringify(skipped.slice(0, 10)));
}
if (leads.length === 0) {
  throw new Error(`All ${records.length} records had unmapped categories — check category field values`);
}

return [{ json: { runKey: `${sourceSystem}-${Date.now()}`, workflowName: 'adl-competitor-leads', sourceSystem, triggerType: 'webhook', startedAt: new Date().toISOString(), completedAt: new Date().toISOString(), leads, _skippedCount: skipped.length } }];
